import {useState, useEffect} from 'react';
import {SolarDay} from 'tyme4ts';
import styles from './App.module.scss';

interface WeatherData {
  temperature: string;
  condition: {
    time: string;
    icon: string;
  }[];
  location: string;
  alerts: string[];
}

function App() {
  const [time, setTime] = useState(new Date());
  const [weather, setWeather] = useState<WeatherData>({
    temperature: '--',
    condition: [],
    location: '武汉',
    alerts: [],
  });

  useEffect(() => {
    async function fetchWeather() {
      try {
        // const response = await fetch('https://p45khwv3hv.re.qweatherapi.com/v7/weather/24h?location=101200101&key=e600bcfccdb54d9eb3814f9257025267');
        const [gridWeatherResponse, alertResponse] = await Promise.all([
          fetch('https://p45khwv3hv.re.qweatherapi.com/v7/grid-weather/24h?location=114.38,30.43&key=e600bcfccdb54d9eb3814f9257025267'),
          fetch('https://p45khwv3hv.re.qweatherapi.com/weatheralert/v1/current/30.43/114.38?key=e600bcfccdb54d9eb3814f9257025267')
        ]);
        const weatherData = await gridWeatherResponse.json();
        const recent8hours: any[] = weatherData.hourly.slice(0, 8);
        const recentTemp = recent8hours.map((hour: any) => parseFloat(hour.temp));
        const maxTemp = Math.max(...recentTemp);
        const minTemp = Math.min(...recentTemp);

        const alertData = await alertResponse.json();
        const validAlerts: string[] = Object.keys(alertData.alerts
          .filter((alert: any) => alert.senderName == '江夏区气象台' && Date.parse(alert.expireTime) > Date.now())
          .map((alert: any) => alert.headline.replace(`${alert.senderName}发布`, ''))
          .reduce((result: any, alertText: string) => {
            result[alertText] = 1;
            return result;
          }, {}));


        setWeather({
          temperature: `${minTemp}~${maxTemp}°C`,
          condition: recent8hours.map((hour) => ({
            time: new Date(Date.parse(hour.fxTime)).toLocaleTimeString('zh-cn').slice(0, 5),
            icon: hour.icon,
          })),
          location: '武汉',
          alerts: validAlerts,
        });
      } catch {
        setWeather({temperature: '获取失败', condition: [], location: '武汉', alerts: []});
      }
    }

    fetchWeather();
    const weatherTimer = setInterval(() => fetchWeather(), 10 * 60 * 1000);
    let secondTimer = setTimeout(() => {
      setTime(new Date())
      secondTimer = setInterval(() => setTime(new Date()), 1000);
    }, 1000 - (new Date()).getMilliseconds());
    return () => {
      clearInterval(weatherTimer);
      clearInterval(secondTimer);
    };
  }, []);

  const year = time.getFullYear();
  const month = time.getMonth() + 1;
  const day = time.getDate();
  const hour = time.getHours();
  const minute = time.getMinutes();
  const second = time.getSeconds();

  const solarDay = SolarDay.fromYmd(year, month, day);
  const lunarDay = solarDay.getLunarDay();
  const lunarMonth = lunarDay.getLunarMonth();

  const lunarMonthStr = lunarMonth.getName();
  const lunarDayStr = lunarDay.getName();

  const solarTerm = solarDay.getTermDay();
  const solarTermStr = solarTerm.getDayIndex() === 0 ? solarTerm.getSolarTerm().getName() : '';

  const formatNumber = (n: number) => n.toString().padStart(2, '0');

  return (
    <div className={styles.wrapper}>
      <div className={styles.container}>
        <div className={styles.weather}
             style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
          {weather.condition.map((condition) => (
            <div key={condition.time} style={{display: 'flex', flexDirection: 'column', alignItems: 'center'}}>
              <i className={`qi-${condition.icon} ${styles.icon}`}></i>
              <span className={styles.hour}>{condition.time}</span>
            </div>
          ))}
        </div>
        <div className={styles.time}>
          <span className={styles.number}><span>{formatNumber(hour)}</span></span>:
          <span className={styles.number}><span>{formatNumber(minute)}</span></span>
          <span style={{fontSize: '20%'}}>:</span>
          <span className={styles.number} style={{fontSize: '20%'}}><span>{formatNumber(second)}</span></span>
        </div>
        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '4vw'}}>
          <div className={styles.date}>
            {`${month}月${day}日 ${lunarMonthStr}${lunarDayStr}${solarTermStr ? ` ${solarTermStr}` : ''}`}
          </div>
          <div className={styles.date}>
            {[...weather.alerts, weather.temperature].join(' ')}
          </div>
        </div>

      </div>
    </div>
  );
}

export default App;
